import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';
import { AuthService } from './auth.service';
import { Task } from '../models/Itask';
@Injectable({
  providedIn: 'root',
})
export class TaskService {
  private apiUrl = 'http://localhost:3000';

  constructor(private http: HttpClient, private authService: AuthService) {}

  getTasks(): Observable<Task[]> {
    // Include user authentication token in the request headers
    const headers = new HttpHeaders().set(
      'Authorization',
      `Bearer ${this.authService.getAuthToken()}`
    );

    // Adjust the endpoint based on your API
    return this.http.get<Task[]>(
      `${this.apiUrl}?userId=${this.authService.getUsername()}`,
      { headers }
    );
  }

  getTaskById(taskId: number): Observable<Task> {
    const headers = new HttpHeaders().set(
      'Authorization',
      `Bearer ${this.authService.getAuthToken()}`
    );
    const url = `${this.apiUrl}/${taskId}`;
    return this.http.get<Task>(url, { headers });
  }

  // addTask(task: Task): Observable<Task> {
  //   // Include user authentication token in the request headers
  //   const headers = new HttpHeaders().set(
  //     'Authorization',
  //     `Bearer ${this.authService.getAuthToken()}`
  //   );

  //   // Ensure that the task has the correct userId
  //   const taskWithUserId = { ...task, userId: this.authService.getUsername() };

  //   return this.http.post<Task>(this.apiUrl, taskWithUserId, { headers });
  // }
  addTask(task: Task): Observable<Task> {
    // Generate a unique id for the new task
    const url = `${this.apiUrl}/tasks`;
    const newTask: Task = { ...task, id: this.generateUniqueId() };

    return this.http.post<Task>(`${this.apiUrl}`, newTask);
  }
  private generateUniqueId(): number {
    // Replace this with your own logic to generate a unique id
    // For simplicity, you can use a timestamp for now
    return new Date().getTime();
  }

  updateTask(task: Task): Observable<Task> {
    const headers = new HttpHeaders().set(
      'Authorization',
      `Bearer ${this.authService.getAuthToken()}`
    );
    const url = `${this.apiUrl}/${task.id}`;

    // Ensure that the task has the correct userId
    const taskWithUserId = { ...task, userId: this.authService.getUsername() };

    return this.http.put<Task>(url, taskWithUserId, { headers });
  }

  deleteTask(taskId: number): Observable<Task> {
    const headers = new HttpHeaders().set(
      'Authorization',
      `Bearer ${this.authService.getAuthToken()}`
    );
    const url = `${this.apiUrl}/${taskId}`;
    return this.http.delete<Task>(url, { headers });
  }
}
